def find_plurality_opinion(concurring_opinions):
    if not concurring_opinions:
        return None
    return max(concurring_opinions.items(), key=lambda x: x[1])

# Example usage:
opinions = {"Justice A": 3, "Justice B": 2, "Justice C": 3}
plurality = find_plurality_opinion(opinions)
print(plurality)  # Output: ('Justice A', 3) or ('Justice C', 3)
